import{_ as n}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as s,c as a,f as t}from"./app.5b5c8f59.js";const p={},e=t(`<h1 id="mybatis" tabindex="-1"><a class="header-anchor" href="#mybatis" aria-hidden="true">#</a> MyBatis</h1><div class="custom-container tip"><p class="custom-container-title">提示</p><p>什么是持久层？</p></div><p>MyBatis是为了解决JDBC无法运用与于大型项目，所以来先介绍一下JDBC。</p><p>什么是JDBC?</p><h2 id="jdbc概述" tabindex="-1"><a class="header-anchor" href="#jdbc概述" aria-hidden="true">#</a> JDBC概述</h2><p>JDBC（Java DataBase Connectivity，java数据库连接）是一种用于执行SQL语句的Java API，可以为多种关系数据库提供统一访问，它由一组用Java语言编写的类和接口组成。JDBC提供了一种基准，据此可以构建更高级的工具和接口，使数据库开发人员能够编写数据库应用程序。以下是<code>JDBC</code>常用的接口。</p><ul><li><p><code>Driver</code></p></li><li><p><code>DriverManager</code></p></li><li><p><code>Connection</code></p></li><li><p><code>Statement</code></p></li><li><p><code>PreparedStatement</code></p></li><li><p><code>ResultSet</code></p></li></ul><h3 id="jdbc运行的流程" tabindex="-1"><a class="header-anchor" href="#jdbc运行的流程" aria-hidden="true">#</a> JDBC运行的流程</h3><p>注册驱动，建立连接，创建传输器，运行SQL语句，处理运行结果，释放资源。</p><p>举一个简单的JDBC程序例子。</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">JDBCTest</span> <span class="token punctuation">{</span>

	<span class="token comment">//加载的mysql的驱动</span>
	<span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">String</span> <span class="token constant">JDBC_DRIVER</span> <span class="token operator">=</span> <span class="token string">&quot;com.mysql.jdbc.Driver&quot;</span><span class="token punctuation">;</span>
	<span class="token comment">//连接数据库的url</span>
	<span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">String</span> <span class="token constant">JDBC_URL</span> <span class="token operator">=</span> <span class="token string">&quot;jdbc:mysql://localhost:3306/test&quot;</span><span class="token punctuation">;</span>
	<span class="token comment">//连接数据库用户名</span>
	<span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">String</span> <span class="token constant">JDBC_USERNAME</span> <span class="token operator">=</span> <span class="token string">&quot;root&quot;</span><span class="token punctuation">;</span>
	<span class="token comment">//数据库密码</span>
	<span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">String</span> <span class="token constant">JDBC_PASSWORD</span> <span class="token operator">=</span> <span class="token string">&quot;123456&quot;</span><span class="token punctuation">;</span>
	<span class="token comment">//测试数据库删除，修改和插入</span>
	<span class="token annotation punctuation">@Test</span>
	<span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">testUpdate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token class-name">Connection</span> connection <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
		<span class="token class-name">PreparedStatement</span> preparedStatement <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
		<span class="token keyword">try</span> <span class="token punctuation">{</span>
			<span class="token comment">// 加载Driver类，注册数据库驱动</span>
			<span class="token class-name">Class</span><span class="token punctuation">.</span><span class="token function">forName</span><span class="token punctuation">(</span><span class="token constant">JDBC_DRIVER</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
			<span class="token comment">// 通过DriverManager,使用url，用户名和密码建立连接(Connection)</span>
			connection <span class="token operator">=</span> <span class="token class-name">DriverManager</span><span class="token punctuation">.</span><span class="token function">getConnection</span><span class="token punctuation">(</span><span class="token constant">JDBC_URL</span><span class="token punctuation">,</span> <span class="token constant">JDBC_USERNAME</span><span class="token punctuation">,</span> <span class="token constant">JDBC_PASSWORD</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
			<span class="token comment">// 通过Connection，使用sql语句打开Statement对象；</span>
			preparedStatement <span class="token operator">=</span> connection<span class="token punctuation">.</span><span class="token function">prepareStatement</span><span class="token punctuation">(</span><span class="token string">&quot;UPDATE student SET age=20 WHERE name=?&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
			<span class="token comment">// 传入参数，防止sql注入</span>
			preparedStatement<span class="token punctuation">.</span><span class="token function">setString</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&quot;xiaoming&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
			<span class="token comment">// 执行语句，将结果返回resultSet</span>
			<span class="token keyword">int</span> count <span class="token operator">=</span> preparedStatement<span class="token punctuation">.</span><span class="token function">executeUpdate</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
			<span class="token comment">// 对结果进行处理</span>
			<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>count<span class="token punctuation">)</span><span class="token punctuation">;</span>
		<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">ClassNotFoundException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
			e<span class="token punctuation">.</span><span class="token function">printStackTrace</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
		<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">SQLException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
			e<span class="token punctuation">.</span><span class="token function">printStackTrace</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
		<span class="token punctuation">}</span> <span class="token keyword">finally</span> <span class="token punctuation">{</span>
			<span class="token comment">// 倒序释放资源</span>
			<span class="token keyword">try</span> <span class="token punctuation">{</span>
				<span class="token keyword">if</span> <span class="token punctuation">(</span>preparedStatement <span class="token operator">!=</span> <span class="token keyword">null</span> <span class="token operator">&amp;&amp;</span> <span class="token operator">!</span>preparedStatement<span class="token punctuation">.</span><span class="token function">isClosed</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
					preparedStatement<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
				<span class="token punctuation">}</span>
			<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">SQLException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
				e<span class="token punctuation">.</span><span class="token function">printStackTrace</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
			<span class="token punctuation">}</span>
			<span class="token keyword">try</span> <span class="token punctuation">{</span>
				<span class="token keyword">if</span> <span class="token punctuation">(</span>connection <span class="token operator">!=</span> <span class="token keyword">null</span> <span class="token operator">&amp;&amp;</span> connection<span class="token punctuation">.</span><span class="token function">isClosed</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
					connection<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
				<span class="token punctuation">}</span>
			<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">SQLException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
				e<span class="token punctuation">.</span><span class="token function">printStackTrace</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
			<span class="token punctuation">}</span>
		<span class="token punctuation">}</span>
	<span class="token punctuation">}</span>


</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="mybatis概述" tabindex="-1"><a class="header-anchor" href="#mybatis概述" aria-hidden="true">#</a> MyBatis概述</h2><p>MyBatis框架支持普通SQL查询、存储及高级映射的持久层框架，几乎消除了JDBC的冗余代码，可以使Java开发人员使用面向对象的编程思想来操作数据库。</p><p>MyBatis是一个<code>ORM</code>框架</p><blockquote><p>什么是ORM？</p></blockquote><blockquote><p>对象关系映射(Object Relational Mapping)是一种为了解决面向对象和关系型数据库存在的互不匹配的现象的技术。</p></blockquote><h2 id="差别" tabindex="-1"><a class="header-anchor" href="#差别" aria-hidden="true">#</a> 差别</h2><h4 id="jdbc工作" tabindex="-1"><a class="header-anchor" href="#jdbc工作" aria-hidden="true">#</a> JDBC工作</h4><p>我们平时使用jdbc进行编程，大致需要下面几个步骤：</p><ol><li>使用jdbc编程需要连接数据库，注册驱动和数据库信息</li><li>操作Connection，打开Statement对象</li><li>通过Statement对象执行SQL，返回结果到ResultSet对象</li><li>使用ResultSet读取数据，然后通过代码转化为具体的POJO对象</li><li>关闭数据库相关的资源</li></ol><h4 id="jdbc的缺点" tabindex="-1"><a class="header-anchor" href="#jdbc的缺点" aria-hidden="true">#</a> jdbc的缺点</h4><ol><li>需要频繁的创建数据库连接</li><li>涉及到的增删改查等功能需要在各个java文件中编写大量代码</li><li>对于底层事务、数据类型转换等都需要手动处理，又是各种代码</li></ol><h4 id="mybatis优点" tabindex="-1"><a class="header-anchor" href="#mybatis优点" aria-hidden="true">#</a> mybatis优点</h4><ol><li>封装了jdbc对数据库的各种操作，减少代码</li><li>增加了连接池、一、二级缓存</li><li>可以自动生成sql语句</li></ol>`,24),c=[e];function o(i,l){return s(),a("div",null,c)}const d=n(p,[["render",o],["__file","db-mybatis-intro.html.vue"]]);export{d as default};
